import { InputField } from "@/components/Form/InputField";
import SelectField from "@/components/Form/SelectField";
import AdminLayout from "@/components/Layout/AdminLayout";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import axios from "axios";
import React, { useEffect, useState } from "react";

export type TProvince = {
  provinceId: string;
  province: string;
};

const AddAddress = () => {
  const [provinceData, setProvinceData] = useState<string[]>([]);
  const province = useCustomSWR("/api/getProvince");

  useEffect(() => {
    if (province.data) {
      const provName = province.data.rajaongkir.results.map(
        (value: TProvince) => value.province
      );

      setProvinceData(provName);
    }
  }, [province.data]);

  const handleOnChangeProvince = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (province.data) {
      const selectedProvince = province.data.rajaongkir.results.find(
        (value: TProvince) => {
          return value.province === e.target.value;
        }
      );
      console.log(selectedProvince);
    }
  };

  return (
    <AdminLayout>
      <h1 className="uppercase font-semibold text-2xl text-black pt-14">
        Add New Address
      </h1>
      <form className="mt-5">
        <InputField
          type="text"
          name="street"
          value={""}
          onChange={() => {}}
          label="Street"
          placeholder="ex: Jl. Ini nama Jalan No. 20, Kuningan, Setiabudi"
        />
        <div className="flex gap-4">
          <SelectField
            id="province"
            name="province"
            onChange={handleOnChangeProvince}
            options={provinceData}
            label="Province"
            defaultValue=""
          />
          <SelectField
            id="city"
            name="city"
            onChange={() => {}}
            options={[]}
            label="City"
          />
        </div>
      </form>
    </AdminLayout>
  );
};

export default AddAddress;
